const allResults = $input.all().map(item => item.json);
const today = new Date().toLocaleDateString('fr-FR', { day: '2-digit', month: '2-digit', year: 'numeric' });
const changedCount = allResults.filter(r => r.changed).length;

const detailsHtml = allResults.map(r => {
  const changesHtml = (r.changes && r.changes !== 'Aucune modification')
    ? `<p><b>Modifications :</b></p><ul>${r.changes.split('\n').filter(Boolean).map(l => `<li>${l.replace(/^[-\u2022\s]+/, '')}</li>`).join('')}</ul>`
    : `<p><i>Aucune modification</i></p>`;
  const obsHtml = r.observation ? `<p><b>Observation :</b> ${r.observation}</p>` : '';
  const badge = r.changed ? ' <span style="color:green">[modifié]</span>' : '';
  return `<h3>${r.fileName}${badge}</h3>${changesHtml}${obsHtml}`;
}).join('<hr>');

const subject = changedCount > 0
  ? `🧠 Autodream - ${changedCount} fichier(s) mis à jour - ${today}`
  : `🧠 Autodream - Rapport mémoire - ${today}`;

const body = `<h2>Autodream — Rapport de consolidation mémoire</h2><p><b>Date :</b> ${today}</p><p>${changedCount > 0 ? changedCount + ' fichier(s) modifié(s)' : 'Aucune modification nécessaire'}</p><h3>Détail par fichier</h3>${detailsHtml}`;

return [{ json: { subject, body } }];

const driveFiles = $input.first().json.files || [];

// Trouver l'ID de MEMORY.md
const memoryMdFile = driveFiles.find(f => f.name === 'MEMORY.md');
const memoryMdId = memoryMdFile ? String(memoryMdFile.id) : '';

// Liste des fichiers .md hors MEMORY.md
const mdFiles = driveFiles
  .filter(f => f.name !== 'MEMORY.md' && f.name.endsWith('.md'))
  .map(f => String(f.name))
  .sort();

const sys = [
  'You are rebuilding the MEMORY.md index file for Claude Code.',
  'MEMORY.md is a master index of all memory files. Each line points to one file.',
  '',
  'Format strictly:',
  '# Memory Index',
  '',
  '- [Title](filename.md) -- one-line description under 120 chars',
  '',
  'Rules:',
  '- Max 200 lines total',
  '- One entry per file, sorted alphabetically',
  '- Description must be specific and actionable, not generic',
  '- Infer the description from the filename (feedback_ = a rule/lesson, project_ = a project state, reference_ = a pointer, user_ = user profile)',
  '- No section headers, no categories, just a flat list',
  '- Output raw markdown ONLY, no backticks, no explanation'
].join('\n');

const userMsg = 'Here are all the current memory files:\n\n' + mdFiles.join('\n') + '\n\nRebuild MEMORY.md as a lean, accurate index.';

const claudeBody = JSON.stringify({
  model: 'claude-sonnet-4-6',
  max_tokens: 2048,
  system: sys,
  messages: [{ role: 'user', content: userMsg }]
});

return [{ json: { claudeBody: claudeBody, memoryMdId: memoryMdId } }];

const raw = $input.first().json.content[0].text;
const memoryMdId = $('Build MEMORY Index').first().json.memoryMdId;

const cleaned = raw
  .replace(/^```markdown\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

return [{ json: { newMemoryContent: cleaned, memoryMdId: String(memoryMdId || '') } }];

const content = String($input.first().json.newMemoryContent || '');
const fileId = String($input.first().json.memoryMdId || '');
// Encoder en base64 pour ConvertToFile toBinary
const b64 = Buffer.from(content, 'utf-8').toString('base64');
return [{ json: { indexContent: content, indexBase64: b64, memFileId: fileId } }];
